### 1. Error Creation Tests
```rust
#[cfg(test)]
mod creation_tests {
    use bubbletea::Error;
    use lipgloss::StyleError;
    use glamour::RenderError;

    #[test]
    fn test_bubbletea_error_variants() {
        // Test each variant can be created
        let e1 = Error::Io(std::io::Error::new(
            std::io::ErrorKind::Other, "test"
        ));
        let e2 = Error::TerminalInit { reason: "failed".into() };
        let e3 = Error::CommandFailed { 
            command: "tick".into(),
            source: None,
        };

        assert!(matches!(e1, Error::Io(_)));
        assert!(matches!(e2, Error::TerminalInit { .. }));
        assert!(matches!(e3, Error::CommandFailed { .. }));
    }

    #[test]
    fn test_lipgloss_error_variants() {
        let e1 = StyleError::InvalidColor { value: "xyz".into() };
        let e2 = StyleError::InvalidDimension { 
            property: "width".into(),
            value: -1,
        };

        assert!(matches!(e1, StyleError::InvalidColor { .. }));
        assert!(matches!(e2, StyleError::InvalidDimension { .. }));
    }

    #[test]
    fn test_glamour_error_variants() {
        let e1 = RenderError::ParseFailed { 
            line: 42,
            reason: "bad markdown".into(),
        };
        let e2 = RenderError::WidthOverflow { 
            content_width: 100,
            available: 80,
        };

        assert!(matches!(e1, RenderError::ParseFailed { .. }));
        assert!(matches!(e2, RenderError::WidthOverflow { .. }));
    }
}
```

