### 3. Error Chaining Tests
```rust
#[cfg(test)]
mod chaining_tests {
    use std::error::Error as StdError;
    use bubbletea::Error;

    #[test]
    fn test_source_chain() {
        let io_err = std::io::Error::new(
            std::io::ErrorKind::NotFound, "file not found"
        );
        let e = Error::Io(io_err);

        // Should have source
        assert!(e.source().is_some());
        let source = e.source().unwrap();
        assert!(source.to_string().contains("not found"));
    }

    #[test]
    fn test_no_source_when_none() {
        let e = Error::TerminalInit { reason: "test".into() };

        // No source for simple variants
        assert!(e.source().is_none());
    }

    #[test]
    fn test_nested_source_chain() {
        // Create 3-level error chain
        let io_err = std::io::Error::new(
            std::io::ErrorKind::Other, "disk failure"
        );
        let mid_err = SomeMiddleError::Io(io_err);
        let top_err = Error::CommandFailed {
            command: "save".into(),
            source: Some(Box::new(mid_err)),
        };

        // Walk the chain
        let mut current: &dyn StdError = &top_err;
        let mut depth = 0;
        while let Some(source) = current.source() {
            current = source;
            depth += 1;
        }

        assert_eq!(depth, 2); // mid_err -> io_err
    }
}
```

