```rust
// crates/wish/tests/common/mod.rs
use std::process::{Command, Stdio};
use tokio::net::TcpListener;

pub struct TestServer {
    port: u16,
    handle: tokio::task::JoinHandle<()>,
    shutdown_tx: tokio::sync::broadcast::Sender<()>,
}

impl TestServer {
    pub async fn start() -> Self {
        // Find available port
        let listener = TcpListener::bind("127.0.0.1:0").await.unwrap();
        let port = listener.local_addr().unwrap().port();
        drop(listener);

        let (shutdown_tx, shutdown_rx) = tokio::sync::broadcast::channel(1);

        let config = WishConfig {
            bind_addr: format!("127.0.0.1:{}", port).parse().unwrap(),
            host_key_path: generate_temp_host_key(),
            ..Default::default()
        };

        let handle = tokio::spawn(async move {
            let server = WishServer::new(config).unwrap();
            server.run_until_shutdown(shutdown_rx).await.unwrap();
        });

        // Wait for server to be ready
        wait_for_port(port).await;

        Self { port, handle, shutdown_tx }
    }

    pub fn port(&self) -> u16 {
        self.port
    }

    pub async fn stop(self) {
        let _ = self.shutdown_tx.send(());
        let _ = self.handle.await;
    }
}

pub struct SshClient {
    port: u16,
    identity_file: Option<PathBuf>,
}

impl SshClient {
    pub fn new(port: u16) -> Self {
        Self { port, identity_file: None }
    }

    pub fn with_identity(mut self, path: PathBuf) -> Self {
        self.identity_file = Some(path);
        self
    }

    pub fn exec(&self, user: &str, command: &str) -> Command {
        let mut cmd = Command::new("ssh");
        cmd.args([
            "-o", "StrictHostKeyChecking=no",
            "-o", "UserKnownHostsFile=/dev/null",
            "-o", "BatchMode=yes",
            "-p", &self.port.to_string(),
        ]);

        if let Some(ref identity) = self.identity_file {
            cmd.args(["-i", identity.to_str().unwrap()]);
        }

        cmd.arg(format!("{}@127.0.0.1", user));
        cmd.arg(command);
        cmd.stdout(Stdio::piped());
        cmd.stderr(Stdio::piped());
        cmd
    }
}
```

