        ..Default::default()
    }).await;

    // Connect but don't send any data
    let mut stream = TcpStream::connect(format!("127.0.0.1:{}", server.port()))
        .await
        .unwrap();

    // Wait for timeout
    tokio::time::sleep(Duration::from_secs(2)).await;

    // Connection should be closed
    let mut buf = [0u8; 1];
