+}
+
+#[derive(bubbletea::Model)]
+struct RegistrationForm {
+    #[state]
+    name: String,
+    #[state]
+    email: String,
+    #[state]
+    age: Option<u32>,
+    #[state]
+    errors: Vec<String>,
+    #[state]
+    submitted: bool,
+    // Non-tracked
+    dirty: bool,
+}
+
+impl RegistrationForm {
+    fn init(&self) -> Option<Cmd> {
+        None
+    }
+
+    fn update(&mut self, msg: Message) -> Option<Cmd> {
+        if let Some(form_msg) = msg.downcast_ref::<FormMsg>() {
+            match form_msg {
+                FormMsg::SetName(n) => {
+                    self.name = n.clone();
+                    self.dirty = true;
+                }
+                FormMsg::SetEmail(e) => {
+                    self.email = e.clone();
+                    self.dirty = true;
+                }
+                FormMsg::SetAge(a) => {
+                    self.age = a.parse().ok();
+                    self.dirty = true;
+                }
+                FormMsg::Submit => {
+                    let validation_errors = self.validate();
+                    if validation_errors.is_empty() {
+                        self.submitted = true;
+                        self.errors.clear();
+                    } else {
+                        self.errors = validation_errors;
+                    }
+                }
+                FormMsg::ClearErrors => {
+                    self.errors.clear();
+                }
+            }
+        }
+        None
+    }
+
+    fn validate(&self) -> Vec<String> {
+        let mut errors = Vec::new();
+
+        if self.name.trim().len() < 2 {
+            errors.push("Name must be at least 2 characters".to_string());
+        }
+
+        if !self.email.contains('@') || !self.email.contains('.') {
+            errors.push("Invalid email format".to_string());
+        }
+
+        if let Some(age) = self.age {
+            if age < 13 || age > 120 {
+                errors.push("Age must be between 13 and 120".to_string());
+            }
+        } else {
+            errors.push("Age is required".to_string());
+        }
+
+        errors
+    }
+
+    fn view(&self) -> String {
+        let mut output = String::from("== Registration Form ==\n\n");
+
+        output.push_str(&format!("Name:  {}\n", self.name));
+        output.push_str(&format!("Email: {}\n", self.email));
+        output.push_str(&format!(
+            "Age:   {}\n",
+            self.age.map(|a| a.to_string()).unwrap_or_default()
+        ));
+
+        if !self.errors.is_empty() {
+            output.push_str("\nErrors:\n");
+            for err in &self.errors {
+                output.push_str(&format!("  - {}\n", err));
+            }
+        }
+
+        if self.submitted {
+            output.push_str("\n[Form submitted successfully!]");
+        }
+
+        output
+    }
+}
