+            let status = if item.enabled { "+" } else { "-" };
+            output.push_str(&format!("{} [{}] {}\n", cursor, status, item.label));
+        }
+
+        output.push_str(&format!("\nContent: {}\n", self.content));
+        output.push_str(&format!(
